const staticData = $getWorkflowStaticData('global');
const lastIdx = Number(staticData.lastSheetRowIndex ?? 1);
const MAX = Math.min(500, Math.max(1, Number($env.GOOGLE_SHEETS_MAX_NEW_PER_RUN || 200)));

function normKey(s) {
  return String(s || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_')
    .replace(/[^a-z0-9_\u0600-\u06ff]/g, '');
}

function pick(row, keys) {
  const entries = Object.entries(row || {});
  const byNorm = {};
  for (const [k, v] of entries) {
    byNorm[normKey(k)] = v;
  }
  for (const key of keys) {
    const v = row[key] ?? byNorm[normKey(key)];
    if (v != null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
}

function mapRow(raw, sheetRow) {
  let name = pick(raw, ['name', 'full_name', 'fullname', 'الاسم', 'الاسم_الكامل', 'اسم', 'customer', 'عميل']);
  let email = pick(raw, ['email', 'e_mail', 'mail', 'البريد', 'الايميل', 'إيميل', 'بريد']);
  let phone = pick(raw, ['phone', 'phone_number', 'mobile', 'tel', 'الجوال', 'الهاتف', 'جوال', 'موبايل', 'هاتف']);
  let company = pick(raw, ['company', 'company_name', 'business', 'الشركة', 'شركة', 'مؤسسة']);

  email = email.toLowerCase();
  phone = phone.replace(/\s+/g, '');

  if (!name) name = 'عميل Google';
  if (!company) company = '—';

  const rowKey = `sheet-${sheetRow}`;
  if (!email && !phone) email = `${rowKey}@google-lead.local`;
  if (!phone) phone = '01000000000';
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) email = `${rowKey}@google-lead.local`;

  return {
    sheet_row: sheetRow,
    sheet_row_key: rowKey,
    name: name.slice(0, 200),
    company: company.slice(0, 200),
    phone,
    email,
    source: 'google',
    raw,
  };
}

const allItems = $input.all();
const newItems = [];
let maxRow = lastIdx;

for (let i = 0; i < allItems.length; i++) {
  const sheetRow = i + 2;
  if (sheetRow <= lastIdx) continue;
  const mapped = mapRow(allItems[i].json, sheetRow);
  newItems.push({ json: mapped });
  maxRow = sheetRow;
  if (newItems.length >= MAX) break;
}

staticData.lastSheetRowIndex = maxRow;

if (newItems.length === 0) {
  return [
    {
      json: {
        _summary: true,
        new_rows: 0,
        last_sheet_row: maxRow,
        total_sheet_rows: allItems.length,
        message: 'No new rows since last sync.',
      },
    },
  ];
}

return newItems;

async function resolveSupabase() {
  let url = '';
  let key = '';
  try {
    const sb = await this.getCredentials('supabaseApi');
    url = String(sb.host || sb.url || '').replace(/\/$/, '');
    key = String(sb.serviceRole || sb.serviceRoleKey || '').trim();
  } catch (_) {}
  if (!url) url = String($env.SUPABASE_URL || '').replace(/\/$/, '');
  if (!key) key = String($env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
  if (!url || !key) {
    throw new Error('ربط Supabase: اختر Credential نوع Supabase API (Host + Service Role) على عقدة Insert، أو Environment.');
  }
  return { url, key };
}
const { url: SUPABASE_URL, key: KEY } = await resolveSupabase.call(this);
const sd = $getWorkflowStaticData('global');
const ASSIGNED = sd.defaultAssignedToId || $env.DEFAULT_ASSIGNED_TO_ID || null;

const headers = {
  apikey: KEY,
  Authorization: `Bearer ${KEY}`,
  'Content-Type': 'application/json',
};

function makeId() {
  return `lead_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

const items = $input.all().filter((i) => !i.json._summary);
const results = [];
let inserted = 0;
let skipped = 0;
let errors = 0;

for (const item of items) {
  const lead = item.json;
  const email = lead.email;
  const phone = lead.phone;

  let existing;
  try {
    const checkUrl = `${SUPABASE_URL}/rest/v1/leads?or=(email.eq.${encodeURIComponent(email)},phone.eq.${encodeURIComponent(phone)})&select=id&limit=1`;
    existing = await this.helpers.httpRequest({ method: 'GET', url: checkUrl, headers, json: true });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'duplicate_check', message: e.message } });
    continue;
  }

  if (Array.isArray(existing) && existing.length > 0) {
    skipped += 1;
    results.push({ json: { ...lead, status: 'skipped_duplicate', existing_id: existing[0].id } });
    continue;
  }

  const id = makeId();
  const now = new Date().toISOString();
  const timeline = [
    {
      id: `ev-google-${id}`,
      leadId: id,
      action: 'استيراد من Google Sheets (n8n)',
      note: `صف الشيت: ${lead.sheet_row}`,
      userId: 'n8n',
      userName: 'تكامل Google',
      createdAt: now,
    },
    {
      id: `a-${id}`,
      leadId: id,
      action: 'إضافة الليد إلى النظام',
      userId: 'n8n',
      userName: 'تكامل Google',
      createdAt: now,
    },
  ];

  const row = {
    id,
    customer_code: null,
    name: lead.name,
    company: lead.company,
    phone: lead.phone,
    email: lead.email,
    status: 'جديد',
    assigned_to_id: ASSIGNED,
    budget: 0,
    company_size: 'صغير',
    source: 'google',
    category: 'إعلانات',
    score: 50,
    follow_up_at: null,
    loss_reason_code: null,
    sla_status: 'مستقر',
    timeline_json: timeline,
    created_at: now,
    updated_at: now,
  };

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/leads`,
      headers: { ...headers, Prefer: 'return=minimal' },
      body: row,
    });
    inserted += 1;
    results.push({ json: { ...lead, status: 'inserted', lead_id: id } });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'insert', message: e.message } });
  }
}

results.push({
  json: {
    _summary: true,
    processed: items.length,
    inserted,
    skipped_duplicate: skipped,
    errors,
  },
});

return results;
